import android.content.Context
import android.content.pm.PackageManager
import android.os.Build
import android.util.Base64
import androidx.security.crypto.EncryptedSharedPreferences
import androidx.security.crypto.MasterKeys
import java.security.SecureRandom
import java.util.concurrent.atomic.AtomicBoolean

class PaymentProcessor(private val context: Context) {
    private val isDeviceIntegrityVerified = AtomicBoolean(false)
    private val encryptedPrefs by lazy {
        val masterKey = MasterKeys.getOrCreate(MasterKeys.AES256_GCM_SPEC)
        EncryptedSharedPreferences.create(
            context,
            "payment_prefs",
            masterKey,
            EncryptedSharedPreferences.PrefKeyEncryptionScheme.AES256_SIV,
            EncryptedSharedPreferences.PrefValueEncryptionScheme.AES256_GCM
        )
    }

    init {
        verifyDeviceIntegrity()
    }

    private fun verifyDeviceIntegrity() {
        val isRooted = isDeviceRooted()
        val isEmulator = isEmulator()
        val isDebuggable = isDebuggable()
        
        if (isRooted || isEmulator || isDebuggable) {
            isDeviceIntegrityVerified.set(false)
            return
        }
        
        isDeviceIntegrityVerified.set(true)
    }

    private fun isDeviceRooted(): Boolean {
        val buildTags = Build.TAGS
        if (buildTags != null && buildTags.contains("test-keys")) {
            return true
        }
        
        val suPath = "/system/bin/su"
        val busyboxPath = "/system/bin/busybox"
        val magiskPath = "/data/data/com.topjohnwu.magisk"
        
        return try {
            listOf(suPath, busyboxPath, magiskPath).any { 
                android.os.FileUtils.getFileDescriptor(it).isValid() 
            }
        } catch (e: Exception) {
            false
        }
    }

    private fun isEmulator(): Boolean {
        return Build.FINGERPRINT.startsWith("generic") ||
                Build.MODEL.contains("google_sdk") ||
                Build.MODEL.contains("Emulator") ||
                Build.MODEL.contains("Android SDK built for x86") ||
                Build.MANUFACTURER.contains("Genymotion") ||
                Build.BRAND.startsWith("generic") && Build.DEVICE.startsWith("generic")
    }

    private fun isDebuggable(): Boolean {
        return context.applicationInfo.flags and android.content.pm.ApplicationInfo.FLAG_DEBUGGABLE != 0
    }

    fun processInAppPurchase(productId: String, amount: Double): Boolean {
        if (!isDeviceIntegrityVerified.get()) {
            throw SecurityException("Device integrity check failed. Purchase blocked.")
        }
        
        return performSecurePayment(productId, amount)
    }

    fun processWalletTransaction(amount: Double, recipient: String): Boolean {
        if (!isDeviceIntegrityVerified.get()) {
            throw SecurityException("Device integrity check failed. Transaction blocked.")
        }
        
        return performSecureWalletTransaction(amount, recipient)
    }

    private fun performSecurePayment(productId: String, amount: Double): Boolean {
        val secureRandom = SecureRandom()
        val transactionId = Base64.encodeToString(ByteArray(16) { secureRandom.nextBytes() }, Base64.NO_WRAP)
        
        encryptedPrefs.edit()
            .putString("last_transaction_id", transactionId)
            .putLong("transaction_timestamp", System.currentTimeMillis())
            .apply()
        
        return true
    }

    private fun performSecureWalletTransaction(amount: Double, recipient: String): Boolean {
        val secureRandom = SecureRandom()
        val transactionId = Base64.encodeToString(ByteArray(16) { secureRandom.nextBytes() }, Base64.NO_WRAP)
        
        encryptedPrefs.edit()
            .putString("last_wallet_transaction_id", transactionId)
            .putLong("wallet_transaction_timestamp", System.currentTimeMillis())
            .apply()
        
        return true
    }

    fun isPaymentAllowed(): Boolean {
